import{_ as e,o as i,c as o,a2 as l}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Calidad, idempotencia y reprocesos","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/pipelines/04-calidad-idempotencia-y-reprocesos.md","filePath":"data-engineering/pipelines/04-calidad-idempotencia-y-reprocesos.md","lastUpdated":1782521464000}'),s={name:"data-engineering/pipelines/04-calidad-idempotencia-y-reprocesos.md"};function n(r,a,t,d,c,p){return i(),o("div",null,[...a[0]||(a[0]=[l(`<h1 id="calidad-idempotencia-y-reprocesos" tabindex="-1">Calidad, idempotencia y reprocesos <a class="header-anchor" href="#calidad-idempotencia-y-reprocesos" aria-label="Permalink to &quot;Calidad, idempotencia y reprocesos&quot;">​</a></h1><p>Un pipeline serio asume que algo fallara: la fuente cambiara, llegaran duplicados, un fichero estara incompleto o una ejecucion se quedara a medias.</p><h2 id="calidad-de-datos" tabindex="-1">Calidad de datos <a class="header-anchor" href="#calidad-de-datos" aria-label="Permalink to &quot;Calidad de datos&quot;">​</a></h2><p>Los controles de calidad detectan datos invalidos antes de que contaminen capas posteriores.</p><p>Validaciones frecuentes:</p><ul><li>Columnas obligatorias.</li><li>Tipos correctos.</li><li>Rangos validos.</li><li>Valores permitidos.</li><li>Claves no nulas.</li><li>Duplicados.</li><li>Integridad referencial.</li><li>Volumen esperado.</li><li>Frescura del dato.</li></ul><p>Ejemplo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>regla: importe &gt;= 0</span></span>
<span class="line"><span>accion si falla: enviar fila a cuarentena</span></span>
<span class="line"><span>severidad: error</span></span></code></pre></div><h2 id="cuarentena" tabindex="-1">Cuarentena <a class="header-anchor" href="#cuarentena" aria-label="Permalink to &quot;Cuarentena&quot;">​</a></h2><p>La cuarentena es una zona donde se guardan registros rechazados con el motivo del fallo.</p><p>Debe incluir:</p><ul><li>Payload original o fila rechazada.</li><li>Regla incumplida.</li><li>Fecha de ejecucion.</li><li>Identificador del pipeline.</li><li>Version del codigo o del flujo.</li><li>Mensaje de error.</li></ul><p>No descartes datos silenciosamente. Lo que hoy parece basura puede ser necesario para depurar una incidencia.</p><h2 id="idempotencia" tabindex="-1">Idempotencia <a class="header-anchor" href="#idempotencia" aria-label="Permalink to &quot;Idempotencia&quot;">​</a></h2><p>Un pipeline es idempotente si puedes ejecutarlo varias veces con la misma entrada y obtener el mismo resultado final.</p><p>Tecnicas habituales:</p><ul><li>Usar claves naturales o ids de evento.</li><li>Escribir por particion y reemplazar solo esa particion.</li><li>Hacer <code>merge</code> en vez de <code>append</code> ciego.</li><li>Deduplicar antes de publicar.</li><li>Registrar lotes procesados.</li><li>Usar nombres de salida deterministas.</li></ul><p>Ejemplo conceptual:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>entrada: ventas del 2026-06-24</span></span>
<span class="line"><span>salida: curated.ventas partition fecha=2026-06-24</span></span>
<span class="line"><span>reproceso: reemplaza solo esa particion</span></span></code></pre></div><h2 id="reintentos" tabindex="-1">Reintentos <a class="header-anchor" href="#reintentos" aria-label="Permalink to &quot;Reintentos&quot;">​</a></h2><p>No todos los fallos son iguales:</p><ul><li><strong>Transitorios:</strong> timeout, red, API temporalmente caida.</li><li><strong>De datos:</strong> campo obligatorio vacio, tipo inesperado.</li><li><strong>De contrato:</strong> columna eliminada o semantica cambiada.</li><li><strong>De capacidad:</strong> falta de memoria, disco o cuota.</li></ul><p>Los fallos transitorios pueden reintentarse. Los fallos de datos deben aislarse o bloquear la publicacion segun criticidad.</p><h2 id="reprocesos" tabindex="-1">Reprocesos <a class="header-anchor" href="#reprocesos" aria-label="Permalink to &quot;Reprocesos&quot;">​</a></h2><p>Un reproceso debe ser una operacion normal, no una aventura.</p><p>Define:</p><ul><li>Que unidad se reprocesa: dia, hora, particion, lote, offset o id.</li><li>Donde esta la entrada original.</li><li>Como se borra o reemplaza la salida.</li><li>Como se evitan duplicados.</li><li>Que downstream debe recalcularse.</li><li>Como se informa al consumidor.</li></ul><h2 id="publicacion-atomica" tabindex="-1">Publicacion atomica <a class="header-anchor" href="#publicacion-atomica" aria-label="Permalink to &quot;Publicacion atomica&quot;">​</a></h2><p>Evita que los consumidores lean datos a medio escribir.</p><p>Estrategias:</p><ul><li>Escribir en tabla temporal y renombrar.</li><li>Escribir particion completa y publicar marcador de exito.</li><li>Usar transacciones si el destino lo soporta.</li><li>Separar zona interna de zona publicada.</li></ul><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Los errores de datos quedan guardados con causa.</li><li>La ejecucion registra version, ventana y parametros.</li><li>Repetir una ejecucion no duplica datos.</li><li>Existe un procedimiento claro de reproceso.</li><li>Los consumidores no ven resultados parciales.</li><li>Hay reglas para decidir si se publica con rechazos o se bloquea.</li></ul>`,33)])])}const h=e(s,[["render",n]]);export{m as __pageData,h as default};
